namespace sv_ba3b2bbf674840d28427f93b682803e8.Models;

// Immutable records for submission
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public bool IsValid =>
        !string.IsNullOrWhiteSpace(FullName) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone) &&
        !string.IsNullOrWhiteSpace(Address);

    public PersonalInfo ToRecord() => new(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim());
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime StartDate { get; set; } = DateTime.Today;
    public DateTime? EndDate { get; set; } = DateTime.Today;
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public bool IsValid =>
        !string.IsNullOrWhiteSpace(Company) &&
        !string.IsNullOrWhiteSpace(Title) &&
        !string.IsNullOrWhiteSpace(Description);

    public WorkEntry ToRecord() => new(
        Company.Trim(), Title.Trim(), StartDate,
        IsCurrent ? null : EndDate, Description.Trim());
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public bool IsValid =>
        !string.IsNullOrWhiteSpace(Name) &&
        !string.IsNullOrWhiteSpace(Relationship) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone);

    public Reference ToRecord() => new(Name.Trim(), Relationship.Trim(), Email.Trim(), Phone.Trim());
}

@* Renders the step progress bar with clickable completed steps *@

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var cssClass = step == CurrentStep ? "step active"
                     : CompletedSteps.Contains(step) ? "step completed"
                     : "step dimmed";

        <button class="@cssClass"
                disabled="@(!CompletedSteps.Contains(step) && step != CurrentStep)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(step == CurrentStep ? "step" : null)">
            <span class="step-number">
                @if (CompletedSteps.Contains(step) && step != CurrentStep)
                {
                    <span class="checkmark" aria-hidden="true">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Count - 1)
        {
            <span class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")" aria-hidden="true"></span>
        }
    }
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlySet<int> CompletedSteps { get; set; } = new HashSet<int>();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
}

@using sv_ba3b2bbf674840d28427f93b682803e8.Models

<fieldset class="work-entry-card">
    <legend>Position @(Index + 1)</legend>

    @if (ShowRemove)
    {
        <button type="button" class="btn-remove" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
    }

    <div class="form-row">
        <div class="form-group">
            <label for="company-@Index">Company Name</label>
            <input id="company-@Index" @bind="Entry.Company" @bind:event="oninput" placeholder="Company name" />
        </div>
        <div class="form-group">
            <label for="title-@Index">Job Title</label>
            <input id="title-@Index" @bind="Entry.Title" @bind:event="oninput" placeholder="Job title" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label for="start-@Index">Start Date</label>
            <input id="start-@Index" type="date" @bind="Entry.StartDate" />
        </div>
        <div class="form-group">
            <label class="checkbox-label">
                <input type="checkbox" @bind="Entry.IsCurrent" /> Currently working here
            </label>
            @if (!Entry.IsCurrent)
            {
                <label for="end-@Index">End Date</label>
                <input id="end-@Index" type="date" @bind="Entry.EndDate" />
            }
        </div>
    </div>

    <div class="form-group">
        <label for="desc-@Index">Description</label>
        <textarea id="desc-@Index" @bind="Entry.Description" @bind:event="oninput"
                  rows="3" placeholder="Describe your responsibilities and achievements"></textarea>
    </div>
</fieldset>

@code {
    [Parameter, EditorRequired] public WorkEntryModel Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@using sv_ba3b2bbf674840d28427f93b682803e8.Models

<fieldset class="reference-card">
    <legend>Reference @(Index + 1)</legend>

    @if (ShowRemove)
    {
        <button type="button" class="btn-remove" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
    }

    <div class="form-row">
        <div class="form-group">
            <label for="ref-name-@Index">Name</label>
            <input id="ref-name-@Index" @bind="Reference.Name" @bind:event="oninput" placeholder="Full name" />
        </div>
        <div class="form-group">
            <label for="ref-rel-@Index">Relationship</label>
            <input id="ref-rel-@Index" @bind="Reference.Relationship" @bind:event="oninput" placeholder="e.g., Manager, Colleague" />
        </div>
    </div>

    <div class="form-row">
        <div class="form-group">
            <label for="ref-email-@Index">Email</label>
            <input id="ref-email-@Index" type="email" @bind="Reference.Email" @bind:event="oninput" placeholder="email@example.com" />
        </div>
        <div class="form-group">
            <label for="ref-phone-@Index">Phone</label>
            <input id="ref-phone-@Index" type="tel" @bind="Reference.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
    </div>
</fieldset>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

