@* Renders the step progress bar with clickable completed steps *@

<nav class="step-indicator" aria-label="Application steps">
    @for (int i = 0; i < StepNames.Count; i++)
    {
        var step = i;
        var cssClass = step == CurrentStep ? "step active"
                     : CompletedSteps.Contains(step) ? "step completed"
                     : "step dimmed";

        <button class="@cssClass"
                disabled="@(!CompletedSteps.Contains(step) && step != CurrentStep)"
                @onclick="() => OnStepClicked.InvokeAsync(step)"
                aria-current="@(step == CurrentStep ? "step" : null)">
            <span class="step-number">
                @if (CompletedSteps.Contains(step) && step != CurrentStep)
                {
                    <span class="checkmark" aria-hidden="true">✓</span>
                }
                else
                {
                    @(step + 1)
                }
            </span>
            <span class="step-label">@StepNames[step]</span>
        </button>

        @if (step < StepNames.Count - 1)
        {
            <span class="step-connector @(CompletedSteps.Contains(step) ? "completed" : "")" aria-hidden="true"></span>
        }
    }
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public IReadOnlySet<int> CompletedSteps { get; set; } = new HashSet<int>();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];
}

