@using sv_ba3b2bbf674840d28427f93b682803e8.Models

<section class="step-content">
    <h2>Personal Information</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner" role="alert">@ErrorMessage</div>
    }

    <div class="form-group">
        <label for="fullname">Full Name <span class="required">*</span></label>
        <input id="fullname" @bind="Model.FullName" @bind:event="oninput" placeholder="Jane Doe" />
    </div>

    <div class="form-group">
        <label for="email">Email <span class="required">*</span></label>
        <input id="email" type="email" @bind="Model.Email" @bind:event="oninput" placeholder="jane@example.com" />
        @if (IsValidatingEmail)
        {
            <span class="validating">Validating email…</span>
        }
    </div>

    <div class="form-group">
        <label for="phone">Phone <span class="required">*</span></label>
        <input id="phone" type="tel" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
    </div>

    <div class="form-group">
        <label for="address">Address <span class="required">*</span></label>
        <textarea id="address" @bind="Model.Address" @bind:event="oninput" rows="2" placeholder="Full mailing address"></textarea>
    </div>

    <div class="step-actions">
        <button class="btn-primary" @onclick="HandleNext" disabled="@IsValidatingEmail">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService ApplicationService { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidatingEmail;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (!Model.IsValid)
        {
            ErrorMessage = "Please fill in all required fields.";
            return;
        }

        IsValidatingEmail = true;
        try
        {
            var emailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address could not be verified. Please check and try again.";
                return;
            }
        }
        finally
        {
            IsValidatingEmail = false;
        }

        await OnNext.InvokeAsync();
    }
}

