@using sv_ba3b2bbf674840d28427f93b682803e8.Models

<section class="step-content">
    <h2>Work History</h2>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner" role="alert">@ErrorMessage</div>
    }

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    <div class="step-actions">
        <button class="btn-outline" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (Entries.Any(e => !e.IsValid))
        {
            ErrorMessage = "Please complete all required fields for each position.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

