@using sv_ba3b2bbf674840d28427f93b682803e8.Models

<section class="step-content">
    <h2>References</h2>
    <p class="hint">Please provide 2–3 professional references.</p>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-banner" role="alert">@ErrorMessage</div>
    }

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Reference="References[index]"
                       Index="index"
                       ShowRemove="References.Count > 2"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button type="button" class="btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    <div class="step-actions">
        <button class="btn-outline" @onclick="OnBack">Back</button>
        <button class="btn-primary" @onclick="HandleNext">Next</button>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
            References.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "Please provide at least 2 references.";
            return;
        }

        if (References.Any(r => !r.IsValid))
        {
            ErrorMessage = "Please complete all fields for each reference.";
            return;
        }

        await OnNext.InvokeAsync();
    }
}

