+
+.char-count.over-limit {
+    color: #ef4444;
+    font-weight: 600;
+}
+
+/* ── Cards (work entries, references) ── */
+.work-entry-card,
+.reference-card {
+    border: 1px solid #e5e7eb;
+    border-radius: 0.375rem;
+    padding: 1rem 1.25rem;
+    margin-bottom: 1rem;
+    position: relative;
+    background: #fafafa;
+}
+
+.work-entry-card legend,
+.reference-card legend {
+    font-weight: 600;
+    font-size: 0.9rem;
+    color: #4f46e5;
+    padding: 0 0.4rem;
+}
+
+/* ── Buttons ── */
+.btn-primary {
+    background: #4f46e5;
+    color: #fff;
+    border: none;
+    padding: 0.6rem 1.5rem;
+    border-radius: 0.375rem;
+    font-size: 0.95rem;
+    font-weight: 500;
+    cursor: pointer;
+    transition: background 0.15s;
+    font-family: inherit;
+}
+
+.btn-primary:hover:not(:disabled) {
+    background: #4338ca;
+}
+
+.btn-primary:disabled {
+    opacity: 0.6;
+    cursor: not-allowed;
+}
+
+.btn-outline {
+    background: #fff;
+    color: #374151;
+    border: 1px solid #d1d5db;
+    padding: 0.6rem 1.5rem;
+    border-radius: 0.375rem;
+    font-size: 0.95rem;
+    font-weight: 500;
+    cursor: pointer;
+    transition: background 0.15s;
+    font-family: inherit;
+}
+
+.btn-outline:hover {
+    background: #f3f4f6;
+}
+
+.btn-secondary {
+    background: none;
+    color: #4f46e5;
+    border: 1px dashed #a5b4fc;
+    padding: 0.5rem 1rem;
+    border-radius: 0.375rem;
+    font-size: 0.9rem;
+    cursor: pointer;
+    margin-bottom: 1rem;
+    font-family: inherit;
+}
+
+.btn-secondary:hover {
+    background: #eef2ff;
+}
+
+.btn-remove {
+    position: absolute;
+    top: -0.7rem;
+    right: 0.5rem;
+    background: #fee2e2;
+    color: #dc2626;
+    border: 1px solid #fca5a5;
+    padding: 0.15rem 0.5rem;
+    border-radius: 0.25rem;
+    font-size: 0.75rem;
+    cursor: pointer;
+    font-family: inherit;
+}
+
+.btn-remove:hover {
+    background: #fecaca;
+}
+
+.btn-link {
+    background: none;
+    border: none;
+    color: #4f46e5;
+    cursor: pointer;
+    font-size: 0.85rem;
+    text-decoration: underline;
+    padding: 0;
+    font-family: inherit;
+}
+
+.btn-link:hover {
+    color: #4338ca;
+}
+
+.btn-submit {
+    padding: 0.75rem 2rem;
+    font-size: 1.05rem;
+}
+
+.step-actions {
+    display: flex;
+    justify-content: flex-end;
+    gap: 0.75rem;
+    margin-top: 1.5rem;
+    padding-top: 1rem;
+    border-top: 1px solid #f3f4f6;
+}
+
+/* ── Errors ── */
+.error-banner {
+    background: #fef2f2;
+    color: #dc2626;
+    border: 1px solid #fecaca;
+    padding: 0.6rem 1rem;
+    border-radius: 0.375rem;
+    margin-bottom: 1rem;
+    font-size: 0.9rem;
+}
+
+/* ── Review Step ── */
+.review-section {
+    border-bottom: 1px solid #f3f4f6;
+    padding-bottom: 1rem;
+    margin-bottom: 1rem;
+}
+
+.review-section:last-of-type {
+    border-bottom: none;
+}
+
+.review-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    margin-bottom: 0.5rem;
+}
+
+.review-header h3 {
+    margin: 0;
+    font-size: 1.05rem;
+    color: #1a1a2e;
+}
+
+.review-section dl {
+    display: grid;
+    grid-template-columns: 8rem 1fr;
+    gap: 0.3rem 1rem;
+    margin: 0;
+}
+
+.review-section dt {
+    font-weight: 500;
+    color: #6b7280;
+    font-size: 0.9rem;
+}
+
+.review-section dd {
+    margin: 0;
+    font-size: 0.9rem;
+}
+
+.review-item {
+    padding: 0.5rem 0;
+    font-size: 0.9rem;
+}
+
+.review-item + .review-item {
+    border-top: 1px dashed #e5e7eb;
+}
+
+.date-range {
+    color: #6b7280;
+    font-size: 0.85rem;
+}
+
+.cover-letter-preview {
+    white-space: pre-wrap;
+    background: #f9fafb;
+    padding: 0.75rem;
+    border-radius: 0.375rem;
+    font-size: 0.9rem;
+    line-height: 1.5;
+    border: 1px solid #f3f4f6;
+}
+
+/* ── Confirmation ── */
+.confirmation {
+    text-align: center;
+    padding: 2rem 1rem;
+}
+
+.confirmation h3 {
+    font-size: 1.5rem;
+    color: #10b981;
+    margin-bottom: 0.75rem;
+}
+
+.confirmation p {
+    color: #374151;
+    font-size: 1rem;
+    margin: 0.5rem 0;
+}
+
+/* ── Responsive ── */
+@media (max-width: 600px) {
+    .form-row {
+        grid-template-columns: 1fr;
+    }
+
+    .step-indicator {
+        gap: 0;
+    }
+
+    .step-label {
+        font-size: 0.65rem;
+    }
+
+    .step-connector {
+        width: 1rem;
+    }
+}
+

